/* ────────────────────────────────────────────────────────────────
   BATCH GENERATION — 1-2 batches per drug, expiry 6m–24m out
──────────────────────────────────────────────────────────────── */
function randInt(lo, hi) { return Math.floor(Math.random() * (hi - lo + 1)) + lo; }
function plusDays(n) { return new Date(Date.now() + n * 86400000); }
function minusDays(n){ return new Date(Date.now() - n * 86400000); }

function generateBatches(drug, supplierIds) {
  const out = [];
  const batchCount = randInt(1, 2);
  for (let i = 0; i < batchCount; i++) {
    const expiryDays = randInt(180, 720);
    const mfgDays    = randInt(30, 270);
    const qty        = randInt(Math.max(20, Math.round(drug.reorderLevel * 0.6)),
                               Math.max(50, Math.round(drug.reorderLevel * 2.2)));
    const purchase   = Math.max(0.5, drug.defaultSalePrice * 0.62);
    const mrp        = Math.round(drug.defaultSalePrice * 1.18 * 100) / 100;
    const supplier   = supplierIds[randInt(0, supplierIds.length - 1)];
    const ymd        = new Date().toISOString().slice(0,10).replace(/-/g, "");
    const batchNo    = `${drug.name.split(" ")[0].substring(0, 3).toUpperCase()}-${ymd}-R${String(i + 1).padStart(2, "0")}${String(randInt(1, 99)).padStart(2, "0")}`;
    out.push({
      drugId: drug._id, drugName: drug.name,
      batchNo,
      expiryDate: plusDays(expiryDays),
      mfgDate:    minusDays(mfgDays),
      quantityIn: qty, remaining: qty,
      purchaseRate: Math.round(purchase * 100) / 100,
      mrp,
      salePrice: drug.defaultSalePrice,
      supplierId: supplier.id, supplierName: supplier.name,
      grnNumber: `GRN-R-${ymd}-${randInt(1000, 9999)}`,
      invoiceNo: `INV/R/${randInt(2025, 2026)}/${randInt(1000, 9999)}`,
      invoiceDate: minusDays(mfgDays - randInt(0, 7)),
      location: "Main Pharmacy",
      createdBy: "Restock script",
    });
  }
  return out;
}

/* ────────────────────────────────────────────────────────────────
   MAIN
──────────────────────────────────────────────────────────────── */
(async () => {
  await connectDB();
  console.log("\n┌──────────────────────────────────────────────────");
  console.log("│  Pharmacy RESTOCK — ", RESTOCK.length, "candidate drugs");
  console.log("└──────────────────────────────────────────────────\n");

  // 0. Optional cleanup of pre-existing test rows
  if (CLEAN_TEST) {
    const before = await Drug.countDocuments({ name: { $in: TEST_NAMES } });
    if (before) {
      const drugs = await Drug.find({ name: { $in: TEST_NAMES } }, "_id").lean();
      const ids = drugs.map(d => d._id);
      await DrugBatch.deleteMany({ drugId: { $in: ids } });
      await Drug.deleteMany({ _id: { $in: ids } });
      console.log(`  ✓ Cleaned ${before} test rows (probe/test/audit entries)\n`);
    }
  }

  // 1. Get suppliers (reuse from base seed)
  const existing = await Supplier.find({ isActive: true }).lean();
  const supplierIds = existing.map(s => ({ id: s._id, name: s.name }));
  if (!supplierIds.length) {
    console.error("  ✗ No suppliers found. Run seedPharmacy.js first.");
    process.exit(1);
  }
  console.log(`  • Using ${supplierIds.length} existing suppliers\n`);

  // 2. Drugs — upsert new, skip existing
  let drugCreated = 0, drugSkipped = 0;
  const newDrugs = [];
  for (const d of RESTOCK) {
    if (BATCHES_ONLY) {
      const e = await Drug.findOne({ name: d.name });
      if (e) newDrugs.push(e);
      continue;
    }
    const e = await Drug.findOne({ name: d.name });
    if (e) { drugSkipped++; continue; }
    const created = await Drug.create({ ...d, createdBy: "Restock script (R7gz)" });
    drugCreated++;
    newDrugs.push(created);
  }
  console.log(`  ✓ Drugs: ${drugCreated} created, ${drugSkipped} already present\n`);

  // 3. Batches
  let batchCreated = 0;
  for (const drug of newDrugs) {
    const has = await DrugBatch.countDocuments({ drugId: drug._id });
    if (has > 0) continue;
    const batches = generateBatches(drug, supplierIds);
    if (batches.length) {
      await DrugBatch.insertMany(batches);
      batchCreated += batches.length;
    }
  }
  console.log(`  ✓ Batches: ${batchCreated} created\n`);

  // 4. Final summary
  const total = await Drug.countDocuments({ isActive: true });
  const byCategory = await Drug.aggregate([
    { $match: { isActive: true } },
    { $group: { _id: "$category", count: { $sum: 1 } } },
    { $sort: { count: -1 } },
  ]);
  console.log(`\n  ★ Active drug count: ${total}`);
  console.log("    By category:");
  byCategory.forEach(c => console.log(`      ${String(c._id || "Other").padEnd(18)} ${c.count}`));

  console.log("\n  Done.\n");
  process.exit(0);
})().catch(e => { console.error(e); process.exit(1); });
